import React from 'react';
import '../styles/components/Projects.css';

function Projects() {
  const projects = [
    {
      title: 'Website Organisasi',
      category: 'Web Development',
      description: 'Membangun website resmi organisasi dengan fitur manajemen anggota, event, dan galeri.',
      tech: ['React', 'Node.js', 'MongoDB'],
      image: '🌐'
    },
    {
      title: 'Aplikasi Absensi',
      category: 'Mobile App',
      description: 'Aplikasi mobile untuk sistem absensi kegiatan organisasi dengan QR Code.',
      tech: ['React Native', 'Firebase'],
      image: '📱'
    },
    {
      title: 'Dashboard Analytics',
      category: 'Data Visualization',
      description: 'Dashboard untuk monitoring dan analisis data kegiatan mahasiswa.',
      tech: ['React', 'Chart.js', 'API'],
      image: '📊'
    },
    {
      title: 'E-Commerce Platform',
      category: 'Web Development',
      description: 'Platform e-commerce untuk UMKM dengan fitur payment gateway.',
      tech: ['React', 'Express', 'PostgreSQL'],
      image: '🛒'
    },
    {
      title: 'Event Management System',
      category: 'Full Stack',
      description: 'Sistem manajemen event terintegrasi untuk keperluan kepanitiaan.',
      tech: ['React', 'Node.js', 'MySQL'],
      image: '🎯'
    },
    {
      title: 'Portfolio Generator',
      category: 'Web App',
      description: 'Tool untuk membuat portfolio website secara otomatis.',
      tech: ['React', 'TailwindCSS'],
      image: '✨'
    }
  ];

  return (
    <section id="projects" className="projects">
      <h2 className="section-title">My Projects</h2>
      <div className="projects-grid">
        {projects.map((project, index) => (
          <div key={index} className="project-card">
            <div className="project-icon">{project.image}</div>
            <div className="project-category">{project.category}</div>
            <h3>{project.title}</h3>
            <p>{project.description}</p>
            <div className="tech-stack">
              {project.tech.map((tech, i) => (
                <span key={i} className="tech-badge">{tech}</span>
              ))}
            </div>
            <button className="btn btn-view">View Details</button>
          </div>
        ))}
      </div>
    </section>
  );
}

export default Projects;
